#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int num1, num2; char op;
        scanf("%d %d %c", &num1, &num2, &op);
        switch (op) {
            case '+': printf("%d\n", num1 + num2); break;
            case '-': printf("%d\n", num1 - num2); break;
            case '*': printf("%d\n", num1 * num2); break;
            case '/': printf("%d\n", num1 / num2); break;
            default:  printf("Error: Invalid operator\n");
        }
    }
    return 0;
}

