import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T + 1):
        a, b, op = data[i].split()
        num1 = int(a)
        num2 = int(b)
        if op == '+':
            out.append(str(num1 + num2))
        elif op == '-':
            out.append(str(num1 - num2))
        elif op == '*':
            out.append(str(num1 * num2))
        elif op == '/':
            out.append(str(num1 // num2))
        else:
            out.append('Error: Invalid operator')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

